<template>
  <div
    class="simple-node"
    :style="{ '--indentation': `${level * 15}` }"
  >
    <div
      class="folder-header"
      @contextmenu.prevent.stop="showContextMenu($event)"
      @dblclick="emitToggle"
      tabindex="0"
      role="button"
      :aria-expanded="isExpanded"
      :aria-label="`Folder ${folder.name}`"
      @keydown.enter="emitSelect"
      @keydown.space="emitToggle"
    >
      <!-- Toggle Icon -->
      <v-icon
        small
        class="toggle-icon"
        @click.stop="emitToggle"
      >
        {{ isExpanded ? 'mdi-chevron-down' : 'mdi-chevron-right' }}
      </v-icon>

      <!-- Folder Icon -->
      <v-icon class="folder-icon">
        {{ isExpanded ? 'mdi-folder-open' : 'mdi-folder' }}
      </v-icon>

      <!-- Folder Name -->
      <span
        class="folder-name"
        @click="emitSelect"
      >
        {{ folder.name }}
      </span>
    </div>

    <!-- Context Menu -->
    <ContextMenu
      v-model:show="isMenuVisible"
      :options="optionsComponent"
    >
      <ContextMenuItem label="Create Subfolder" @click="handleMenuAction('create')" />
      <ContextMenuItem label="Rename Folder" @click="handleMenuAction('rename')" />
      <ContextMenuItem label="Delete Folder" @click="handleMenuAction('delete')" />
    </ContextMenu>

    <transition name="expand">
      <div v-if="isExpanded && folder.children.length" class="children">
        <SimpleNode
          v-for="(child) in folder.children"
          :key="child._id"
          :folder="child"
          :selected-folder-path="selectedFolderPath"
          :level="level + 1"
          @fetch-files="(...args) => $emit('fetch-files', ...args)"
          @select-folder="(...args) => $emit('select-folder', ...args)"
          @toggle-folder="(...args) => $emit('toggle-folder', ...args)"
          @create-folder="(...args) => $emit('create-folder', ...args)"
          @rename-folder="(...args) => $emit('rename-folder', ...args)"
          @delete-folder="(...args) => $emit('delete-folder', ...args)"
        />
      </div>
    </transition>
  </div>
</template>

<script>
import { ContextMenu, ContextMenuItem } from '@imengyu/vue3-context-menu';  // Import components
import { debounce } from 'lodash';

export default {
  name: 'SimpleNode',
  components: {
    ContextMenu,
    ContextMenuItem,
  },
  props: {
    folder: {
      type: Object,
      required: true,
    },
    selectedFolderPath: {
      type: String,
      required: true,
    },
    level: {
      type: Number,
      default: 0, // Default to root level
    },
  },
  data() {
    return {
      isMenuVisible: false,
      optionsComponent: {
        x: 0,
        y: 0,
        zIndex: 9999,
      },
    };
  },
  computed: {
    isSelected() {
      return this.folder.path === this.selectedFolderPath;
    },
    isExpanded() {
      return this.folder.isExpanded;
    },
  },
  methods: {
    emitToggle: debounce(function () {
      this.$emit('toggle-folder', this.folder.path);
    }, 300),

    emitSelect() {
      this.$emit('select-folder', this.folder);
    },

    showContextMenu(event) {
      event.preventDefault();
      event.stopPropagation();
      this.optionsComponent.x = event.clientX;
      this.optionsComponent.y = event.clientY;
      this.isMenuVisible = true;
    },

    handleMenuAction(action) {
      const folderPath = this.folder.path;
      switch (action) {
        case 'rename':
          this.renameFolder(folderPath);
          break;
        case 'delete':
          this.deleteFolder(folderPath);
          break;
        case 'create':
          this.$emit('create-folder', folderPath);
          break;
        default:
          break;
      }
      this.isMenuVisible = false;
    },

    renameFolder() {
      const newName = prompt('Enter the new name for the folder:', this.folder.name);
      if (newName && newName.trim() !== '') {
        this.$emit('rename-folder', this.folder.path, newName.trim());
      }
    },

    deleteFolder(path) {
      this.$emit('delete-folder', path);
    },

    createSubFolder(parentPath) {
      this.$emit('create-folder', parentPath);
    },
  },
};
</script>

<style scoped>
.simple-node {
  margin-left: calc(var(--indentation) * 1px);
  padding: 5px 10px;
  transition: background-color 0.3s ease;
}

.folder-header {
  display: flex;
  align-items: center;
  padding: 5px;
  border-radius: 4px;
  transition: background-color 0.3s ease;
}

.folder-header:hover {
  background-color: #1d593f; /* Slightly lighter shade on hover */
}

.folder-icon {
  margin-right: 8px;
  color: #f0d500; /* Bright yellow for folder icons */
}

.folder-name {
  flex-grow: 1;
  color: #ffffff;
  font-weight: 500;
}

.folder-name:hover {
  color: #cce7d0;
}

.selected .folder-header {
  background-color: #18211e;
  color: #ffffff;
}

.children {
  margin-left: calc(var(--indentation) * 1px);
}

/* Expand transition */
.expand-enter-active,
.expand-leave-active {
  transition: max-height 0.3s ease-out, opacity 0.3s ease-out;
}

.expand-enter-from,
.expand-leave-to {
  max-height: 0;
  opacity: 0;
}
</style>
