<template>
  <div class="explorer-container">
<!-- Header: Navigation Buttons and Path -->
<div class="header">
  <div class="button-container">
    <!-- Navigation Buttons -->
    <v-btn icon @click="goBack" :disabled="!canGoBack">
      <v-icon>mdi-arrow-left</v-icon>
    </v-btn>
    <v-btn icon @click="goForward" :disabled="!canGoForward">
      <v-icon>mdi-arrow-right</v-icon>
    </v-btn>
    <v-btn icon @click="goUp" :disabled="!canGoUp">
      <v-icon>mdi-arrow-up</v-icon>
    </v-btn>

    <!-- Dynamically Resizing Path Input -->
    <div class="path-input-container">
      <v-text-field
        v-if="currentFolderPath"
        v-model="editableFolderPath"
        
        variant="outlined" 
        density="compact" 
        hide-details
        placeholder="Enter folder path"
        @keyup.enter="navigateToPath"
        :style="{ width: `${inputWidth}px` }"
      />
    </div>
  </div>
</div>



    <!-- Main Layout -->
    <div class="layout">
      <!-- Resizable Left Pane: Folder Structure -->
      <div
        class="left-pane"
        :style="{ width: `${leftPaneWidth}px` }"
        @contextmenu.prevent="showGlobalContextMenu($event)"
      >
        <h3>Folder Structure</h3>
        <SimpleNode
          v-for="folder in folderStructure"
          :key="folder._id"
          :folder="folder"
          :selected-folder-path="currentFolderPath"
          :level="0"
          @fetch-files="fetchFiles"
          @select-folder="handleSelectFolder"
          @toggle-folder="toggleFolder"
          @create-folder="createSubFolder"
          @rename-folder="renameFolder"
          @delete-folder="deleteFolder"
        />
      </div>

      <!-- Resizable Divider -->
      <div
        class="divider"
        @mousedown="startResizing"
      ></div>

      <!-- Right Pane: File or Content Display -->
      <div class="right-pane" @contextmenu.prevent="showRightPaneContextMenu($event)">
        <div>
          <div v-if="isLoadingFiles">
            <v-progress-circular indeterminate></v-progress-circular>
          </div>
          <ul v-else-if="files.length > 0">
            <li
              v-for="file in files"
              :key="file._id" 
              class="file-item"
              @mouseover="hoverFile(file)"
              @mouseleave="hoverFile(null)"
              @click="selectFile(file)"
              @contextmenu.prevent="(event) => { 
                console.log('Right-clicked file:', file); 
                showFileContextMenu(event, file); 
              }"
              :class="{ 
                'selected': selectedFile && selectedFile._id === file._id,
                'hovered': hoveredFile && hoveredFile._id === file._id 
              }"
            >
            <v-icon>{{ getFileIcon(file.contentType) }}</v-icon>
              {{ file.filename }}
            </li>
          </ul>

          <!-- Context Menu for Files -->
          <ContextMenu
            v-if="showFileContextMenuVisible"
            v-model:show="showFileContextMenuVisible"
            :options="optionsFileContextMenu"
          >
            <ContextMenuItem label="Download" @click="downloadFile(selectedFile)" />
            <ContextMenuItem label="Rename" @click="renameFile(selectedFile)" />
            <ContextMenuItem label="Delete" @click="deleteFile(selectedFile)" />
          </ContextMenu>

          <!-- Context Menu for Right Pane -->
          <ContextMenu
            v-if="showRightPaneContextMenuVisible"
            v-model:show="showRightPaneContextMenuVisible"
            :options="optionsRightPaneContextMenu"
          >
            <ContextMenuItem label="Upload File" @click="uploadFile()" />
            <!-- Add more options as needed -->
          </ContextMenu>
        </div>
      </div>
    </div>

    <!-- Context Menu for Root-Level Creation -->
    <ContextMenu
      v-model:show="showRootContextMenu"
      :options="optionsRootContextMenu"
    >
      <ContextMenuItem label="Create Root Folder" @click="handleCreateRootFolder" />
    </ContextMenu>

    <!-- Folder Creation Dialog -->
    <v-dialog v-model="showCreateFolderDialog" persistent max-width="500">
      <v-card>
        <v-card-title>Create New Folder</v-card-title>
        <v-card-text>
          <!-- Folder Name Input -->
          <v-text-field label="Folder Name" v-model="newFolderName" required></v-text-field>
          <!-- Folder Type Selection -->
          <v-radio-group v-model="selectedFolderType" label="Select Folder Type" mandatory>
            <v-radio label="Organizational" value="organizational"></v-radio>
            <v-radio label="Storage" value="storage"></v-radio>
            <v-radio label="Category" value="category"></v-radio>
            <v-radio 
              label="Subcategory" 
              value="subcategory" 
              v-if="isCurrentFolderCategory"
            ></v-radio>
          </v-radio-group>
          <!-- Show storage type selection only if 'Storage' is selected -->
          <v-select 
            v-if="selectedFolderType === 'storage'" 
            v-model="selectedStorageType" 
            :items="['Image', 'Document']" 
            label="Select Storage Type" 
            placeholder="Choose storage type"
          ></v-select>
        </v-card-text>
        <v-card-actions>
          <v-btn color="blue darken-1" text @click="createFolder">Create</v-btn>
          <v-btn color="red darken-1" text @click="showCreateFolderDialog = false">Cancel</v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </div>
</template>

<script>
import axios from 'axios';
import SimpleNode from './SimpleNode.vue';
import { ContextMenu, ContextMenuItem } from '@imengyu/vue3-context-menu';
import {
  VBtn,
  VIcon,
  VDialog,
  VCard,
  VCardTitle,
  VCardText,
  VCardActions,
  VTextField,
  VRadioGroup,
  VRadio,
  VSelect,
  VProgressCircular,
} from 'vuetify/components';

export default {
  components: {
    SimpleNode,
    ContextMenu,
    ContextMenuItem,
    VBtn,
    VIcon,
    VDialog,
    VCard,
    VCardTitle,
    VCardText,
    VCardActions,
    VTextField,
    VRadioGroup,
    VRadio,
    VSelect,
    VProgressCircular
  },
  data() {
    return {
      editableFolderPath: this.currentFolderPath,
      leftPaneWidth: 300, // Default width for the left pane
      isResizing: false,
      history: [], // Stores the navigation history
      historyIndex: -1, // Tracks the current index in the history
      currentFolderPath: 'local_disk', // Initialize to root
      files: [], // Array to store files of the selected folder  
      isLoadingFiles: false,
      folderStructure: [], // Populate this from backend data
      showCreateFolderDialog: false,
      newFolderName: '',
      hoveredFile: null, // New property for tracking hovered file
      selectedFolderType: 'organizational', // Default to 'organizational'
      selectedStorageType: '', // To store 'Image' or 'Document' if 'Storage' is selected
      showRootContextMenu: false, // Flag to show the root context menu
      optionsRootContextMenu: {
        x: 0,
        y: 0,
        zIndex: 9999,
      },
      showFileContextMenuVisible: false,
      selectedFile: null,
      optionsFileContextMenu: {
        x: 0,
        y: 0,
        zIndex: 9999,
      },
      showRightPaneContextMenuVisible: false,
      optionsRightPaneContextMenu: {
        x: 0,
        y: 0,
        zIndex: 9999,
      },
      currentFolder: {}, // Tracks the currently selected folder
    };
  },
  computed: {
    inputWidth() {
    const baseWidth = 150; // Minimum width in pixels
    const charWidth = 8; // Approximate width of a character in pixels
    return Math.max(baseWidth, this.editableFolderPath.length * charWidth);
  },
    isCurrentFolderCategory() {
      return this.currentFolder && this.currentFolder.type === "category";
    },
    canGoBack() {
      return this.historyIndex > 0;
    },
    canGoForward() {
      return this.historyIndex < this.history.length - 1;
    },
    canGoUp() {
      return this.currentFolderPath && this.currentFolderPath.includes('/');
    }
  },
  watch: {
  currentFolderPath(newPath) {
    // Keep the editableFolderPath synced with currentFolderPath
    this.editableFolderPath = newPath;
  },
},
  methods: {
    navigateToPath() {
      if (this.editableFolderPath !== this.currentFolderPath) {
        console.log('Navigating to:', this.editableFolderPath);
        // Call a method to navigate to the entered path
        this.handleSelectFolder({ path: this.editableFolderPath });
      }
    },
    startResizing() {
      this.isResizing = true;

      const onMouseMove = (e) => {
        const newWidth = Math.max(200, e.clientX); // Minimum width of 200px
        this.leftPaneWidth = Math.min(newWidth, window.innerWidth - 300); // Prevent overlapping right pane
      };

      const onMouseUp = () => {
        this.isResizing = false;
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
      };

      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', onMouseUp);
    },

    // Navigation Methods
    goBack() {
      if (this.canGoBack) {
        this.historyIndex--;
        const previousPath = this.history[this.historyIndex];
        this.updateCurrentFolder(previousPath, false); // Update without adding to history
        console.log('Went back to:', previousPath);
        console.log('History Index:', this.historyIndex);
      }
    },

    goForward() {
      if (this.canGoForward) {
        this.historyIndex++;
        const nextPath = this.history[this.historyIndex];
        this.updateCurrentFolder(nextPath, false); // Update without adding to history
        console.log('Went forward to:', nextPath);
        console.log('History Index:', this.historyIndex);
      }
    },

    goUp() {
      if (this.canGoUp) {
        const parentPath = this.currentFolderPath.substring(0, this.currentFolderPath.lastIndexOf('/'));
        this.updateCurrentFolder(parentPath, true);
        console.log('Went up to:', parentPath);
      }
    },

    // File Selection Methods
    selectFile(file) {
      this.selectedFile = file;
      console.log('File selected:', file);
    },
    hoverFile(file) {
      this.hoveredFile = file;
    },

    toggleFolder(path) {
      const toggleFolderRecursively = (folders) => {
        for (const folder of folders) {
          if (folder.path === path) {
            folder.isExpanded = !folder.isExpanded; // Toggle the isExpanded state
            console.log(`Toggled folder "${folder.name}":`, folder.isExpanded);
            break; // Stop after finding the folder
          } else if (folder.children && folder.children.length > 0) {
            toggleFolderRecursively(folder.children);
          }
        }
      };

      toggleFolderRecursively(this.folderStructure);
      // No need to reassign folderStructure in Vue 3
    },




    // Context Menu Methods
    showRightPaneContextMenu(event) {
      event.preventDefault();
      // Ensure that the right-pane context menu only shows when clicking on an empty space
      if (!event.target.closest('.file-item')) {
        this.selectedFile = null; // No file is selected
        this.optionsRightPaneContextMenu.x = event.clientX;
        this.optionsRightPaneContextMenu.y = event.clientY;
        this.showRightPaneContextMenuVisible = true;

        // Close other context menus if open
        this.showFileContextMenuVisible = false;
      }
    },

    showFileContextMenu(event, file) {
      event.preventDefault();
      event.stopPropagation(); 
      this.selectedFile = file;
      console.log('Context menu for file:', file);
      this.optionsFileContextMenu.x = event.clientX;
      this.optionsFileContextMenu.y = event.clientY;
      this.showFileContextMenuVisible = true;
      console.log('Context menu for file:', file); // Add debug log
      // Close other context menus if open
      this.showRightPaneContextMenuVisible = false;
    },



    downloadFile(file) {
      if (!file) return; // Add this check
      // Implement file download logic
      console.log('Downloading file:', file);
    },

    // Fetch Files
    async fetchFiles(folderPath = '') {
  console.log('Fetching files for path:', folderPath); // Log folderPath
  this.isLoadingFiles = true;
  try {
    const response = await axios.get('/api/files/get-files', {
      params: { path: folderPath },
    });
    console.log('Response from backend:', response.data); // Log backend response
    this.files = response.data;
    console.log('Files updated:', this.files); // Log updated files
  } catch (error) {
    console.error('Error fetching files:', error);
    alert(error.response?.data?.message || 'Failed to fetch files. Please try again.');
    this.files = [];
  } finally {
    this.isLoadingFiles = false;
  }
}
,


    getFileIcon(fileType) {
  if (!fileType) return 'mdi-file';

  // Handle extensions (e.g., 'pdf', 'docx')
  const extension = fileType.toLowerCase();
  if (['pdf'].includes(extension)) return 'mdi-file-pdf';
  if (['docx', 'doc'].includes(extension)) return 'mdi-file-word';
  if (['txt'].includes(extension)) return 'mdi-file-document-outline';

  // Handle MIME types (e.g., 'application/pdf', 'text/plain')
  if (extension.includes('pdf')) return 'mdi-file-pdf';
  if (extension.includes('word')) return 'mdi-file-word';
  if (extension.includes('text')) return 'mdi-file-document-outline';

  // Default icon
  return 'mdi-file';
},


// Delete File
async deleteFile(file) {
  if (!confirm(`Are you sure you want to delete the file: "${file.filename}"? This action cannot be undone.`)) {
    return;
  }
  try {
    // Call the delete endpoint
    const response = await axios.delete('/api/files/delete-file', {
      data: {
        path: this.currentFolderPath, // Pass the folder path
        fileId: file._id, // Pass the file's unique ID
      },
    });

    console.log(response.data.message);

    // Show confirmation popup
    alert('File deleted successfully.');

    // Trigger file refresh after the user closes the popup
    this.fetchFiles(this.currentFolderPath);
  } catch (error) {
    console.error('Error deleting file:', error);
    alert(error.response?.data?.message || 'Failed to delete file. Please try again.');
  }
},




    // Fetch Folder Structure
    async fetchFolderStructure() {
      try {
        const response = await axios.get('/api/folders/folder-structure');
        this.folderStructure = this.addIsExpanded(response.data);
        console.log('Fetched folder structure:', JSON.stringify(this.folderStructure, null, 2));
      } catch (error) {
        console.error('Error fetching folder structure:', error);
      }
    },

    // Update Folder Expansion
    updateFolderExpansion() {
      const expandFolders = (folders, path) => {
        folders.forEach(folder => {
          if (path === folder.path || path.startsWith(`${folder.path}/`)) {
            folder.isExpanded = true; // Ensure ancestor folders are expanded
            if (folder.children) {
              expandFolders(folder.children, path);
            }
          }
          // Do not set isExpanded to false for other folders
        });
      };
      expandFolders(this.folderStructure, this.currentFolderPath);
    },


    // Add `isExpanded` Property to Folders
    addIsExpanded(folders) {
      return folders.map(folder => {
        folder.isExpanded = false; // Direct assignment
        if (folder.children) {
          folder.children = this.addIsExpanded(folder.children);
        }
        return folder;
      });
    },

    // Combined Handler for Folder Selection
    handleSelectFolder(folder) {
    console.log('Folder selected:', folder); // Debugging
    this.updateCurrentFolder(folder, true);
  },

    // Update Current Folder and Path
    updateCurrentFolder(folder, addToHistory = true) {
      if (!folder) return;

      const path = folder.path;

      if (path !== this.currentFolderPath) {
        console.log(`Updating current folder to: ${folder.name} (${path})`);
        this.currentFolderPath = path;
        this.selectedFolderPath = path;

        if (addToHistory) {
          if (this.historyIndex < this.history.length - 1) {
            this.history = this.history.slice(0, this.historyIndex + 1);
          }
          this.history.push(path);
          this.historyIndex = this.history.length - 1;
        }

        console.log('Updated navigation history:', this.history);
        this.fetchFiles(path); // Fetch files only if the path changes
      }

      this.currentFolder = folder;
      console.log('Set current folder object:', this.currentFolder);

      // Expand folders in the tree
      this.updateFolderExpansion();
    },


    // Reset Current Folder Path
    resetCurrentFolderPath() {
      this.currentFolderPath = 'local_disk'; // Reset to root path
      this.currentFolder = null;
      console.log('Reset currentFolderPath to root.');
      this.fetchFiles(this.currentFolderPath);
      this.fetchFolderStructure();
    },

    /**
     * Handles creating a subfolder from the context menu.
     * @param {String} parentPath - The path of the parent folder.
     */
    createSubFolder(parentPath) {
      // Find the parent folder object based on parentPath
      const findFolder = (folders, targetPath) => {
        for (const folder of folders) {
          if (folder.path === targetPath) {
            return folder;
          }
          if (folder.children && folder.children.length > 0) {
            const found = findFolder(folder.children, targetPath);
            if (found) return found;
          }
        }
        return null;
      };

      const parentFolder = findFolder(this.folderStructure, parentPath);
      if (parentFolder) {
        this.updateCurrentFolder(parentFolder, false); // Set as current folder
        this.showCreateFolderDialog = true;
      } else {
        alert('Parent folder not found.');
      }
    },

    async createFolderAPI(folderData) {
  try {
    const response = await axios.post('/api/folders/create-folder', folderData);
    console.log('Folder created successfully:', response.data.folder);

    // Update the folder structure after creation
    await this.fetchFolderStructure();

    // Find the parent folder to maintain the current view
    const parentFolder = this.findFolderByPath(this.folderStructure, folderData.parentPath);

    if (parentFolder) {
      console.log('Maintaining current folder path as:', parentFolder.path);
      this.updateCurrentFolder(parentFolder, false); // Stay in the parent folder
      this.currentFolderPath = parentFolder.path; // Ensure currentFolderPath is correctly set
      this.fetchFiles(parentFolder.path); // Update the right pane
    } else {
      console.warn('Parent folder not found after creation.');
    }
  } catch (error) {
    console.error('Error creating folder:', error);
    alert(error.response?.data?.message || 'Failed to create folder.');
  }
},


  /**
   * Handles renaming a file from the context menu.
   * @param {Object} file - The file object to be renamed.
   * @param {String} file.id - The unique identifier of the file.
   * @param {String} file.name - The current name of the file.
   * @param {String|null} file.bucketName - The bucket name associated with the file (if any).
   */
   async renameFile(file) {
      if (!file) return;

      const newName = prompt('Enter the new name for the file:', file.name);
      if (newName && newName.trim() !== '') {
        try {
          console.log(`Renaming file ID "${file.id}" to "${newName.trim()}" in folder path "${this.currentFolder.path}"`);

          const response = await axios.put('/api/files/rename-file', {
            fileId: file.id,
            newName: newName.trim(),
            folderPath: this.currentFolder.path, // Pass folderPath only
          });

          console.log(response.data.message);
          alert('File renamed successfully!');

          // Refresh the file list to reflect the change
          this.fetchFiles(this.currentFolderPath);
        } catch (error) {
          console.error('Error renaming file:', error);
          alert(error.response?.data?.message || 'Failed to rename file. Please try again.');
        }
      }
    },




    /**
     * Handles deleting a folder from the context menu.
     * @param {String} path - The path of the folder to delete.
     */
    deleteFolder(path) {
      this.deleteFolderAPI(path);
    },

      /**
       * Handles renaming a folder from the context menu.
       * @param {String} oldPath - The current path of the folder.
       * @param {String} newName - The new name for the folder.
       */
       renameFolder(oldPath, newName) {
        console.log('renameFolder called with:', { oldPath, newName }); // Debugging log
        this.renameFolderAPI(oldPath, newName);
      },

      /**

       * Calls the backend API to rename a folder.
       * @param {String} oldPath - The current path of the folder.
       * @param {String} newName - The new name for the folder.
       */
       async renameFolderAPI(oldPath, newName) {
          try {
            const response = await axios.put('/api/folders/rename-folder', { oldPath, newName });
            console.log(response.data.message);
            
            // Refresh the folder structure
            this.fetchFolderStructure();

            // Check if the renamed folder is the current folder
            if (this.currentFolderPath === oldPath) {
              this.currentFolderPath = oldPath.replace(/[^/]+$/, newName); // Update current folder path
              this.fetchFiles(this.currentFolderPath); // Refresh files for the renamed folder
            }
          } catch (error) {
            console.error('Error renaming folder:', error);
            alert(error.response?.data?.message || 'Failed to rename folder. Please try again.');
          }
        },



        async uploadFile() {
          try {
            const fileInput = document.createElement('input');
            fileInput.type = 'file';
            fileInput.multiple = true;

            fileInput.onchange = async (event) => {
              const files = event.target.files;
              if (files.length === 0) return;

              // Create FormData object
              const formData = new FormData();
              for (let i = 0; i < files.length; i++) {
                formData.append('files', files[i]);
              }
              formData.append('path', this.currentFolderPath); // Include the current folder path

              this.isLoadingFiles = true;

              try {
                const response = await axios.post('/api/files/upload-file', formData, {
                  headers: {
                    'Content-Type': 'multipart/form-data',
                  },
                });
                console.log('Files uploaded successfully:', response.data);
                alert('Files uploaded successfully!');
                this.fetchFiles(this.currentFolderPath); // Refresh files
              } catch (error) {
                console.error('Error uploading files:', error);
                alert(error.response?.data?.message || 'Failed to upload files. Please try again.');
              } finally {
                this.isLoadingFiles = false;
              }
            };

            fileInput.click();
          } catch (error) {
            console.error('Unexpected error during file upload:', error);
            alert('An unexpected error occurred during file upload.');
          }
        },


/**
 * Calls the backend API to delete a folder.
 * @param {String} path - The path of the folder to delete.
 */
 async deleteFolderAPI(path) {
  try {
    // Make an initial API call to check the folder state
    const validationResponse = await axios.post('/api/folders/check-folder', { path });
    const folderInfo = validationResponse.data;

    // Handle case where the folder contains files
    if (folderInfo.containsFiles) {
      const userConfirmed = confirm(
        `The folder contains ${folderInfo.fileCount} files. Are you sure you want to delete the folder, including all files?`
      );

      if (!userConfirmed) {
        alert('Folder deletion canceled.');
        return;
      }
    }

    // Handle case where the folder contains subfolders
    if (folderInfo.hasSubfolders) {
      const userConfirmed = confirm(
        `The folder contains subfolders. Are you sure you want to delete the folder, including all subfolders?`
      );

      if (!userConfirmed) {
        alert('Folder deletion canceled.');
        return;
      }
    }

    // Show confirmation for empty folders
    const finalConfirmation = confirm(
      `Are you sure you want to delete the folder: "${path}"? This action cannot be undone.`
    );

    if (!finalConfirmation) {
      alert('Folder deletion canceled.');
      return;
    }

    // Proceed with deletion if all confirmations are accepted
    const deleteResponse = await axios.delete('/api/folders/delete-folder', { data: { path } });
    console.log(deleteResponse.data.message);
    alert(deleteResponse.data.message); // Show success message
    this.fetchFolderStructure(); // Refresh the folder structure
  } catch (error) {
    console.error('Error during folder deletion:', error);

    // Handle validation or deletion errors
    if (error.response?.data?.message) {
      alert(error.response.data.message); // Show backend-specific error message
    } else {
      alert('Failed to delete folder. Please try again.');
    }
  }
},

    // Folder Creation Methods
    async createFolder() {
      if (!this.newFolderName) {
        alert('Please enter a folder name');
        return;
      }

      // Determine which endpoint to use based on folder type
      const isCategoryType = this.selectedFolderType === 'category' || this.selectedFolderType === 'subcategory';
      const endpoint = isCategoryType ? '/api/folders/create-category-folder' : '/api/folders/create-folder';
      
      const payload = isCategoryType ? {
        name: this.newFolderName,
        type: this.selectedFolderType, // "category" or "subcategory"
        parentId: this.currentFolder ? this.currentFolder._id : null,
      } : {
        path: this.currentFolderPath ? `${this.currentFolderPath}/${this.newFolderName}` : this.newFolderName,
        type: this.selectedFolderType, // "organizational" or "storage"
        storageType: this.selectedFolderType === 'storage' ? this.selectedStorageType : null,
      };

      try {
        const response = await axios.post(endpoint, payload);
        console.log('Folder created successfully:', response.data);

        // Refresh folder structure
        await this.fetchFolderStructure();

        // If it's a category, navigate into it
        if (isCategoryType && this.selectedFolderType === 'category') {
          this.updateCurrentFolder(response.data.folder, true); // Pass the entire folder object
        }
      } catch (error) {
        console.error('Error creating folder:', error);
        alert(error.response.data.message || 'Failed to create folder. Please try again.');
      } finally {
        this.showCreateFolderDialog = false;
        this.newFolderName = '';
        this.selectedFolderType = 'organizational';
        this.selectedStorageType = '';
      }
    },

    // Global Context Menu Methods
    showGlobalContextMenu(event) {
      event.preventDefault();
      if (event && event.target && event.target.classList.contains('left-pane')) {
        this.optionsRootContextMenu.x = event.clientX;
        this.optionsRootContextMenu.y = event.clientY;
        this.showRootContextMenu = true;
      } else {
        this.showRootContextMenu = false;
      }
    },

    handleCreateRootFolder() {
      this.resetCurrentFolderPath(); // Navigate to root
      this.showCreateFolderDialog = true;
      this.showRootContextMenu = false;
    },
  },
  mounted() {
    this.fetchFolderStructure();
    this.fetchFiles(this.currentFolderPath);

    // Initialize history if it's empty
    if (this.history.length === 0) {
      this.history.push(this.currentFolderPath);
      this.historyIndex = 0;
    }

    // Debugging logs
    console.log('Component mounted.');
    console.log('Initial History:', this.history);
    console.log('History Index:', this.historyIndex);
  },
};
</script>

