<template>
  <v-card class="pa-4 custom-card-height" outlined>
    <v-text variant="h5" class="custom-title">Document Types Distribution</v-text>
    <div class="chart-container">
      <apexchart
        type="bar"
        height="350"
        :options="chartOptions"
        :series="chartSeries"
      />
    </div>
  </v-card>
</template>

<script>
import VueApexCharts from 'vue3-apexcharts';
import { ref, watch, onMounted } from 'vue';
// Import the color function from your new file
import { getColorForDocumentType } from '@/utils/documentColors';

export default {
  components: {
    apexchart: VueApexCharts,
  },
  props: {
    documentTypesData: {
      type: Array,
      required: true,
    },
  },
  setup(props) {
    const chartOptions = ref({});
    const chartSeries = ref([]);

    const updateChart = () => {
      // Log original document types from props
      console.log("Original document types from props:", props.documentTypesData.map(item => item.type));

      const labels = props.documentTypesData.map(item => item.type);
      const data = props.documentTypesData.map(item => item.count);

      // Assign colors to document types using the consistent color scheme
      const colors = labels.map(label => {
        const color = getColorForDocumentType(label);
        console.log(`Document Type: ${label}, Assigned Color: ${color}`); // Log each document type and color
        return color;
      });

      // Set chart options
      chartOptions.value = {
        chart: {
          type: 'bar',
        },
        colors: colors, // Apply consistent colors from documentTypeColors
        plotOptions: {
          bar: {
            horizontal: false,
            distributed: true, // Enable distributed colors
            dataLabels: {
              enabled: false,
            },
          },
        },
        xaxis: {
          categories: labels,
          title: {
            text: 'Document Types',
          },
          labels: {
            rotate: -45,
            style: {
              fontSize: '12px',
            },
          },
        },
        yaxis: {
          title: {
            text: 'Count',
          },
        },
        tooltip: {
          y: {
            formatter: val => `${val} documents`,
          },
        },
      };

      // Set chart series data
      chartSeries.value = [
        {
          name: 'Document Count',
          data: data,
        },
      ];
    };



    // Watch for changes in documentTypesData and update the chart
    watch(
      () => props.documentTypesData,
      () => {
        updateChart();
      },
      { immediate: true }
    );

    // Update chart on component mount
    onMounted(() => {
      updateChart();
    });

    return {
      chartOptions,
      chartSeries,
    };
  },
};
</script>


<style scoped>
.custom-card-height {
  height: 400px;
}

.chart-container {
  height: 350px;
}

.custom-title {
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 16px;
}
</style>
